import{_ as i,c as l}from"./app.f21a7cce.js";const e={},r=l('<h1 id="\u4E00\u4E9B\u7F29\u5199" tabindex="-1"><a class="header-anchor" href="#\u4E00\u4E9B\u7F29\u5199" aria-hidden="true">#</a> \u4E00\u4E9B\u7F29\u5199</h1><ol><li>SKU\uFF1ASKU=Stock Keeping Unit(\u5E93\u5B58\u91CF\u5355\u4F4D) \uFF0C\u5373\u5E93\u5B58\u8FDB\u51FA\u8BA1\u91CF\u7684\u5355\u4F4D;\u4EE5\u670D\u88C5\u4E3A\u4F8B\u53EF\u4EE5\u662F\u4EE5\u4EF6\u4E3A\u5355\u4F4D\u3002</li><li>KPI\uFF1A\u5173\u952E\u7EE9\u6548\u6307\u6807\u6CD5(Key Performance Indicator\uFF0CKPI)\uFF0C\u5B83\u628A\u5BF9\u7EE9\u6548\u7684\u8BC4\u4F30\u7B80\u5316\u4E3A\u5BF9\u51E0\u4E2A\u5173\u952E\u6307\u6807\u7684\u8003\u6838\uFF0C\u5C06\u5173\u952E\u6307\u6807\u5F53\u4F5C\u8BC4\u4F30\u6807\u51C6\uFF0C\u628A\u5458\u5DE5\u7684\u7EE9\u6548\u4E0E\u5173\u952E\u6307\u6807\u4F5C\u51FA\u6BD4\u8F83\u5730\u8BC4\u4F30\u65B9\u6CD5\u3002</li><li>VMD\uFF1A\u6211\u4EEC\u4E00\u822C\u628A\u5B83\u53EB\u505A\u201C\u89C6\u89C9\u8425\u9500\u201D\u6216\u8005\u201C\u5546\u54C1\u8BA1\u5212\u89C6\u89C9\u5316\u201D\u3002VMD \u4E0D\u4EC5\u4EC5\u6D89\u53CA\u5230\u9648\u5217\u3001\u88C5\u9970\u3001\u5C55\u793A\u3001\u9500\u552E\u7684\u5356\u573A\u95EE\u9898\uFF0C\u8FD8\u6D89\u53CA\u5230\u4F01\u4E1A\u7406\u5FF5\u4EE5\u53CA\u7ECF\u8425\u4F53\u7CFB\u7B49\u91CD\u8981\u201C\u6218\u7565\u201D\uFF0C\u9700\u8981\u8DE8\u90E8\u95E8\u7684\u4E13\u4E1A\u77E5\u8BC6\u548C\u6280\u80FD\uFF0C\u5E76\u4E0D\u662F\u901A\u5E38\u610F\u4E49\u4E0A\u6211\u4EEC\u72ED\u4E49\u7406\u89E3\u7684\u201C\u5C55\u793A\u3001\u9648\u5217\u201D\uFF0C\u800C\u5B9E\u9645\u5B83\u5E94\u8BE5\u662F\u5E7F\u4E49\u4E0A\u201C\u5305\u542B\u73AF\u5883\u4EE5\u53CA\u5546\u54C1\u7684\u5E97\u94FA\u6574\u4F53\u8868\u73B0\u201D\u3002</li><li>VP \u89C6\u89C9\u9648\u5217\uFF1A\u4F5C\u7528\u2014\u8868\u8FBE\u5E97\u94FA\u5356\u573A\u7684\u6574\u4F53\u5370\u8C61\uFF0C\u5F15\u5BFC\u987E\u5BA2\u8FDB\u4EBA\u5E97\u5185\u5356\u573A\uFF0C\u6CE8\u91CD\u60C5\u666F\u6C1B\u56F4\u8425\u9020\uFF0C\u5F3A\u8C03\u4E3B\u9898\u3002VP \u662F\u5438\u5F15\u987E\u5BA2\u7B2C\u4E00\u89C6\u7EBF\u7684\u91CD\u8981\u6F14\u793A\u7A7A\u95F4\u3002\u5730\u70B9\u662F\u6A71\u7A97\u3001\u5356\u573A\u5165\u53E3\u3001\u4E2D\u5C9B\u5C55\u53F0\u3001\u5E73\u9762\u5C55\u684C\u7B49\u3002\u7531\u8BBE\u8BA1\u5E08\u3001\u9648\u5217\u5E08\u8D1F\u8D23\u3002</li><li>PP \u552E\u70B9\u9648\u5217 \uFF1A\u4F5C\u7528\u2014\u8868\u8FBE\u533A\u57DF\u5356\u573A\u7684\u5370\u8C61\uFF0C\u5F15\u5BFC\u987E\u5BA2\u8FDB\u4EBA\u5404\u4E13\u67DC\u5356\u573A\u6DF1\u5904\uFF0C\u5C55\u793A\u5546\u54C1\u7684\u7279\u5F81\u548C\u642D\u914D\uFF0C\u5C55\u793A\u4E0E\u5B9E\u9645\u9500\u552E\u5546\u54C1\u7684\u5173\u8054\u6027\u3002PP \u662F\u987E\u5BA2\u8FDB\u5165\u5E97\u94FA\u540E\u89C6\u7EBF\u4E3B\u8981\u96C6\u4E2D\u7684\u533A\u57DF\uFF0C\u662F\u5546\u54C1\u5356\u70B9\u7684\u4E3B\u8981\u5C55\u793A\u533A\u57DF\u3002\u5730\u70B9\u662F\u5C55\u67DC\u3001\u5C55\u67B6\u3001\u6A21\u7279\u3001\u5356\u573A\u67F1\u4F53\u7B49\u3002\u7531\u5BFC\u8D2D\u5458\u8D1F\u8D23\u3002</li><li>IP \u5355\u54C1\u9648\u5217\uFF1A\u4F5C\u7528\u2014\u5C06\u5B9E\u9645\u9500\u552E\u5546\u54C1\u7684\u5206\u7C7B\u3001\u6574\u7406\uFF0C\u4EE5\u5546\u54C1\u6446\u653E\u4E3A\u4E3B\u3002\u6E05\u6670\u3001\u6613\u63A5\u89E6\u3001\u6613\u9009\u62E9\u3001\u6613\u9500\u552E\u7684\u9648\u5217\u3002IP \u662F\u4E3B\u8981\u7684\u50A8\u5B58\u7A7A\u95F4\uFF0C\u662F\u987E\u5BA2\u6700\u540E\u5F62\u6210\u6D88\u8D39\u7684\u5FC5\u8981\u89E6\u53CA\u7684\u7A7A\u95F4\uFF0C\u4E5F\u53EB\u505A\u5BB9\u91CF\u533A\u3002\u5730\u70B9\u662F\u5C55\u67DC\u3001\u5C55\u67B6\u7B49\u3002\u7531\u5BFC\u8D2D\u5458\u8D1F\u8D23\u3002</li><li>\u589E\u957F\u7387\uFF1A\u9500\u552E\u589E\u957F\u7387=(\u4E00\u5468\u671F\u5185)\u9500\u552E\u91D1\u989D\u6216\u6570\u91CF/(\u4E0A\u4E00\u5468\u671F)\u9500\u552E\u91D1\u989D\u6216\u6570\u91CF-1\u3002\u73AF\u6BD4\u589E\u957F\u7387=(\u62A5\u544A\u671F-\u57FA\u671F)/\u57FA\u671F \xD7100%\u3002</li><li>\u6BDB\u5229\u7387\uFF1A\u9500\u552E\u6BDB\u5229\u7387=\u5B9E\u73B0\u6BDB\u5229\u989D/\u5B9E\u73B0\u9500\u552E\u989D \xD7 100%\u3002</li><li>\u8001\u987E\u5BA2\u8D21\u732E\u7387\uFF1A\u5982\u679C\u4E00\u5BB6\u5E97\u94FA\u4E00\u5E74\u6709 50 \u4E07\u6BDB\u5229\uFF0C\u5176\u4E2D\u8001\u5BA2\u6237\u6D88\u8D39\u4EA7\u751F\u6BDB\u5229 40 \u4E07;\u65B0\u5BA2\u6237\u4EA7\u751F\u6BDB\u5229 10 \u4E07;\u90A3\u4E48\u8FD9\u5BB6\u5E97\u94FA\u7684\u8001\u5BA2\u6237\u8D21\u732E\u7387\u662F 80%;\u65B0\u5BA2\u6237\u8D21\u732E\u7387\u662F 20%;</li><li>\u54C1\u7C7B\u652F\u6301\u7387=\u67D0\u54C1\u7C7B\u9500\u552E\u6570\u6216\u91D1\u989D \xF7 \u5168\u54C1\u7C7B\u9500\u552E\u6570\u6216\u91D1\u989D \xD7 100%\u3002</li><li>\u52A8\u9500\u6BD4\uFF1A\u52A8\u9500\u6BD4\uFF0C\u5373\u52A8\u9500\u7387\u3002\u516C\u5F0F\u4E3A\uFF1A(\u4E00\u4E2A\u5468\u671F\u5185)\u5E93\u5B58/\u5468\u671F\u5185\u65E5\u5747\u9500\u91CF\u3002\u5B58\u9500\u6BD4\u7684\u8BBE\u7F6E\u662F\u5426\u79D1\u5B66\u5408\u7406\uFF0C\u4E00\u662F\u51B3\u5B9A\u4E86\u8BA2\u5355\u4F9B\u8D27\u662F\u5426\u80FD\u591F\u771F\u6B63\u5B9E\u73B0\u5411\u8BA2\u5355\u751F\u4EA7\u5EF6\u4F38;\u4E8C\u662F\u4F01\u4E1A\u662F\u5426\u80FD\u591F\u771F\u6B63\u505A\u5230\u9002\u5E94\u5E02\u573A\u3001\u5C0A\u91CD\u5E02\u573A\uFF0C\u54CD\u5E94\u8BA2\u5355;\u4E09\u662F\u5728\u7BA1\u7406\u65F6\u5E93\u5B58\u4F01\u4E1A\u80FD\u5426\u771F\u6B63\u505A\u5230\u6EE1\u8DB3\u5E02\u573A\u3001\u4E0D\u79EF\u538B\u3001\u4E0D\u65AD\u6863\u3002</li><li>\u52A8\u9500\u7387\uFF1A\u516C\u5F0F\u4E3A\uFF1A\u52A8\u9500\u54C1\u9879\u6570/\u5E93\u5B58\u54C1\u9879\u6570 \xD7 100%\u3002\u52A8\u9500\u54C1\u9879\uFF1A\u4E3A\u672C\u6708\u5B9E\u73B0\u9500\u552E\u7684\u6240\u6709\u5546\u54C1(\u53BB\u9664\u4E0D\u8BA1\u6BDB\u5229\u5546\u54C1)\u6570\u91CF\u3002\u5E93\u5B58\u91D1\u989D\uFF1A\u4E3A\u6708\u5EA6\u6BCF\u5929\u603B\u5E93\u6709\u5E93\u5B58\u7684\u6240\u6709\u5546\u54C1\u9500\u552E\u91D1\u989D\u7684\u5E73\u5747\u503C(\u540A\u724C\u96F6\u552E\u989D)\u3002</li><li>\u5E93\u9500\u6BD4\uFF1A\u7B49\u4E8E(\u4E00\u4E2A\u5468\u671F\u5185)\u672C\u671F\u8FDB\u8D27\u91CF/\u671F\u672B\u5E93\u5B58\u3002\u662F\u4E00\u4E2A\u68C0\u6D4B\u5E93\u5B58\u91CF\u662F\u5426\u5408\u7406\u7684\u6307\u6807,\u5982\u6708\u5E93\u9500\u6BD4,\u5E74\u5E73\u5747\u5E93\u9500\u6BD4\u7B49,\u8BA1\u7B97\u65B9\u6CD5:\u6708\u5E93\u9500\u6BD4,\u6708\u5E73\u5747\u5E93\u5B58\u91CF/\u6708\u9500\u552E\u989D\u5E74\u5E73\u5747\u5E93\u9500\u6BD4, \u5E74\u5E73\u5747\u5E93\u5B58\u91CF/\u5E74\u9500\u552E\u989D,\u6BD4\u7387\u9AD8\u8BF4\u660E\u5E93\u5B58\u91CF\u8FC7\u5927,\u9500\u552E\u4E0D\u7545,\u8FC7\u4F4E\u5219\u53EF\u80FD\u662F\u751F\u4EA7\u8DDF\u4E0D\u4E0A\u3002</li><li>\u5B58\u9500\u6BD4\uFF1A\u5B58\u9500\u6BD4\u662F\u6307\u5728\u4E00\u4E2A\u5468\u671F\u5185\uFF0C\u5546\u54C1\u5E93\u5B58\u4E0E\u5468\u671F\u5185\u65E5\u5747\u9500\u91CF\u7684\u6BD4\u503C\uFF0C\u662F\u7528\u5929\u6570\u6765\u53CD\u6620\u5546\u54C1\u5373\u65F6\u5E93\u5B58\u72B6\u51B5\u7684\u76F8\u5BF9\u6570\u3002\u800C\u66F4\u4E3A\u7CBE\u786E\u7684\u6CD5\u5219\u662F\u4F7F\u7528\u65E5\u5747\u5E93\u5B58\u548C\u65E5\u5747\u9500\u552E\u7684\u6570\u636E\u6765\u8BA1\u7B97\uFF0C\u4ECE\u800C\u53CD\u6620\u5F53\u524D\u7684\u5E93\u5B58\u9500\u552E\u6BD4\u4F8B\u3002\u8D8A\u662F\u7545\u9500\u7684\u5546\u54C1\uFF0C\u6211\u4EEC\u9700\u8981\u8BBE\u7F6E\u7684\u5B58\u9500\u6BD4\u8D8A\u5C0F\uFF0C\u8FD9\u5C31\u80FD\u66F4\u597D\u5730\u52A0\u5FEB\u5546\u54C1\u7684\u5468\u8F6C\u6548\u7387;\u8D8A\u662F\u6EDE\u9500\u7684\u5546\u54C1\uFF0C\u5B58\u9500\u6BD4\u5C31\u8D8A\u5927\u3002\u5B58\u9500\u6BD4\u4E00\u822C\u6309\u7167\u6708\u4EFD\u6765\u8BA1\u7B97\uFF0C\u8BA1\u7B97\u516C\u5F0F\u662F\uFF1A\u6708\u672B\u5E93\u5B58/\u6708\u603B\u9500\u552E\u3002\u8BA1\u7B97\u5355\u4F4D\u53EF\u4EE5\u662F\u6570\u91CF\uFF0C\u4E5F\u53EF\u4EE5\u662F\u91D1\u989D\uFF0C\u76EE\u524D\u4F01\u4E1A\u591A\u7528\u6570\u91CF\u6765\u8BA1\u7B97\u3002\u6BD4\u5982\u8FD9\u4E2A\u6708\u672B\u7684\u5E93\u5B58\u662F 900 \u4EF6\uFF0C\u800C\u8FD9\u4E2A\u6708\u603B\u8BA1\u9500\u552E\u4E86 300 \u4EF6\uFF0C\u5219\u672C\u6708\u7684\u5B58\u9500\u6BD4\u4E3A 900/300=3 \u4E2A\u4EBA\u4EE5\u4E3A\uFF0C\u4EE5\u91D1\u989D\u6765\u8BA1\u7B97\u6BD4\u8F83\u5408\u7406\uFF0C\u6BD5\u7ADF\u5E93\u5B58\u5728\u8D22\u52A1\u62A5\u8868\u4E0A\u662F\u4EE5\u91D1\u989D\u7684\u5F62\u5F0F\u5B58\u5728\u7684\u3002</li><li>\u552E\u7F44\u7387=(\u4E00\u4E2A\u5468\u671F\u5185)\u9500\u552E\u4EF6\u6570/\u8FDB\u8D27\u4EF6\u6570\uFF0C\u7545\u9500\u7684\u4EA7\u54C1\u662F\u4E0D\u9700\u4FC3\u9500\u7684\uFF0C\u53EA\u6709\u6EDE\u9500\u7684\u4EA7\u54C1\u624D\u9700\u8981\u4FC3\u9500\u3002\u6EDE\u9500\u4EA7\u54C1\u53EF\u901A\u8FC7\u552E\u7F44\u7387\u6765\u786E\u5B9A\u3002\u4E00\u822C\u800C\u8A00\uFF0C\u670D\u88C5\u7684\u9500\u552E\u751F\u547D\u5468\u671F\u4E3A 3 \u4E2A\u6708;\u5982\u679C\u5728\u4E09\u4E2A\u6708\u5185\uFF0C\u4E0D\u662F\u56E0\u4E3A\u5B63\u8282\u3001\u5929\u6C14\u7B49\u539F\u56E0\uFF0C\u8863\u670D\u7684\u552E\u7F44\u7387\u4F4E\u4E8E 60%\uFF0C\u5219\u5927\u81F4\u53EF\u5224\u65AD\u6B64\u4EA7\u54C1\u7684\u9500\u552E\u662F\u6709\u95EE\u9898\u7684\uFF0C\u5F53\u7136\u4E5F\u4E0D\u5FC5\u7B49\u5230\u4E09\u4E2A\u6708\u540E\u624D\u53EF\u4EE5\u786E\u5B9A\uFF0C\u4E00\u822C\u800C\u8A00\uFF0C\u4E09\u4E2A\u6708\u5185\uFF0C\u7B2C\u4E00\u4E2A\u6708\u5C3A\u7801\u3001\u914D\u8272\u9F50\u5168\uFF0C\u552E\u7F44\u7387\u4F1A\u4E3A 40 \uFF5E 50%\uFF0C\u7B2C\u4E8C\u4E2A\u6708\u7EA6\u4E3A 20 \uFF5E 25%\uFF0C\u7B2C\u4E09\u4E2A\u6708\u56E0\u4E3A\u65AD\u7801\u7B49\u539F\u56E0\uFF0C\u552E\u7F44\u7387\u53EA\u4F1A\u6709 5 \uFF5E 10%\u3002\u5F53\u7B2C\u4E00\u4E2A\u6708\u7684\u552E\u7F44\u7387\u5927\u5927\u4F4E\u4E8E 40%\u65F6\uFF0C\u4E14\u65E0\u5176\u4ED6\u539F\u56E0\u65F6\uFF0C\u5C31\u6709\u5FC5\u8981\u7279\u522B\u5173\u6CE8\uFF0C\u52A0\u5F3A\u9648\u5217\u6216\u8FDB\u884C\u63A8\u5E7F\u4E86\u3002</li><li>\u76C8\u4E8F\u5E73\u8861\u70B9\uFF1A\u76C8\u4E8F\u5E73\u8861\u70B9(\u7B80\u79F0 BEP)\u53C8\u79F0\u96F6\u5229\u6DA6\u70B9\u3001\u4FDD\u672C\u70B9\u3001\u76C8\u4E8F\u4E34\u754C\u70B9\u3001\u635F\u76CA\u5206\u6B67\u70B9\u3001\u6536\u76CA\u8F6C\u6298\u70B9\u3002\u901A\u5E38\u662F\u6307\u5168\u90E8\u9500\u552E\u6536\u5165\u7B49\u4E8E\u5168\u90E8\u6210\u672C\u65F6(\u9500\u552E\u6536\u5165\u7EBF\u4E0E\u603B\u6210\u672C\u7EBF\u7684\u4EA4\u70B9)\u7684\u4EA7\u91CF\u3002\u4EE5\u76C8\u4E8F\u5E73\u8861\u70B9\u7684\u754C\u9650\uFF0C\u5F53\u9500\u552E\u6536\u5165\u9AD8\u4E8E\u76C8\u4E8F\u5E73\u8861\u70B9\u65F6\u4F01\u4E1A\u76C8\u5229\uFF0C\u53CD\u4E4B\uFF0C\u4F01\u4E1A\u5C31\u4E8F\u635F\u3002\u76C8\u4E8F\u5E73\u8861\u70B9\u53EF\u4EE5\u7528\u9500\u552E\u91CF\u6765\u8868\u793A\uFF0C\u5373\u76C8\u4E8F\u5E73\u8861\u70B9\u7684\u9500\u552E\u91CF;\u4E5F\u53EF\u4EE5\u7528\u9500\u552E\u989D\u6765\u8868\u793A\uFF0C\u5373\u76C8\u4E8F\u5E73\u8861\u70B9\u7684\u9500\u552E\u989D\u3002\u6309\u5B9E\u7269\u5355\u4F4D\u8BA1\u7B97\uFF1A\u76C8\u4E8F\u5E73\u8861\u70B9=\u56FA\u5B9A\u6210\u672C/(\u5355\u4F4D\u4EA7\u54C1\u9500\u552E\u6536\u5165-\u5355\u4F4D\u4EA7\u54C1\u53D8\u52A8\u6210\u672C)\u6309\u91D1\u989D\u8BA1\u7B97\uFF1A\u76C8\u4E8F\u5E73\u8861\u70B9=\u56FA\u5B9A\u6210\u672C/(1-\u53D8\u52A8\u6210\u672C/\u9500\u552E\u6536\u5165)=\u56FA\u5B9A\u6210\u672C/\u8D21\u732E\u6BDB\u7387\u3002</li><li>\u6CE2\u6BB5\uFF1A\u670D\u88C5\u4F01\u4E1A\u5728\u5E97\u94FA\u4E0A\u65B0\u8D27\u7684\u6279\u6B21\uFF0C\u4E00\u822C\u4EBA\u4F1A\u8BA4\u4E3A\uFF0C\u6625\u3001\u590F\u3001\u79CB\u3001\u51AC\u56DB\u4E2A\u5B63\u8282\u5C31\u662F\u5929\u7136\u7684\u4E0A\u8D27\u6CE2\u6BB5\uFF0C\u5982\u679C\u54C1\u724C\u5728\u5168\u56FD\u5404\u5730\u6709\u591A\u5BB6\u5E97\uFF0C\u5C31\u8981\u7ED3\u5408\u5F53\u5730\u7684\u6C14\u6E29\u53D8\u5316\u4E0A\u8D27\u3002</li><li>\u5E93\u5B58\u5468\u8F6C\u7387\uFF1A\u7B49\u4E8E(\u4E00\u4E2A\u5468\u671F\u5185)\u9500\u552E\u8D27\u54C1\u6210\u672C/\u5B58\u8D27\u6210\u672C\u3002\u5E93\u5B58\u5929\u6570=365 \u5929 \xF7 \u5546\u54C1\u5468\u8F6C\u7387\u3002\u4FA7\u91CD\u4E8E\u53CD\u6620\u4F01\u4E1A\u5B58\u8D27\u9500\u552E\u7684\u901F\u5EA6\uFF0C\u5B83\u5BF9\u4E8E\u7814\u5224\u7279\u5B9A\u4F01\u4E1A\u6D41\u52A8\u8D44\u91D1\u7684\u8FD0\u7528\u53CA\u6D41\u8F6C\u72B6\u51B5\u5F88\u6709\u5E2E\u52A9\u3002\u5176\u7ECF\u6D4E\u542B\u4E49\u662F\u53CD\u6620\u4F01\u4E1A\u5B58\u8D27\u5728\u4E00\u5E74\u4E4B\u5185\u5468\u8F6C\u7684\u6B21\u6570\u3002\u4ECE\u7406\u8BBA\u4E0A\u8BF4\uFF0C\u5B58\u8D27\u5468\u8F6C\u6B21\u6570\u8D8A\u9AD8\uFF0C\u4F01\u4E1A\u7684\u6D41\u52A8\u8D44\u4EA7\u7BA1\u7406\u6C34\u5E73\u53CA\u4EA7\u54C1\u9500\u552E\u60C5\u51B5\u4E5F\u5C31\u8D8A\u597D\u3002</li><li>\u5E73\u6548\uFF1A\u5C31\u662F\u6307\u7EC8\u7AEF\u5356\u573A 1 \u5E73\u7C73\u7684\u6548\u7387\uFF0C\u4E00\u822C\u662F\u4F5C\u4E3A\u8BC4\u4F30\u5356\u573A\u5B9E\u529B\u7684\u4E00\u4E2A\u91CD\u8981\u6807\u51C6\u3002\u5E73\u6548 = \u9500\u552E\u4E1A\u7EE9 \xF7 \u5E97\u94FA\u9762\u79EF\u3002</li><li>\u4EA4\u53C9\u6BD4\u7387\uFF1A\u4EA4\u53C9\u6BD4\u7387\u901A\u5E38\u4EE5\u6BCF\u5B63\u4E3A\u8BA1\u7B97\u5468\u671F\uFF0C\u4EA4\u53C9\u6BD4\u7387\u4F4E\u7684\u4F18\u5148\u6DD8\u6C70\u5546\u54C1\u3002\u4EA4\u53C9\u6BD4\u7387\u6570\u503C\u6108\u5927\u6108\u597D\uFF0C\u56E0\u5B83\u540C\u65F6\u517C\u987E\u5546\u54C1\u7684\u6BDB\u5229\u7387\u53CA\u5468\u8F6C\u7387\uFF0C\u5176\u6570\u503C\u6108\u5927\uFF0C\u8868\u793A\u6BDB\u5229\u7387\u9AD8\u4E14\u5468\u8F6C\u53C8\u5FEB\u3002\u4EA4\u53C9\u6BD4\u7387=\u6BDB\u5229\u7387 \xD7 \u5468\u8F6C\u7387\u3002</li><li>\u5B63\u8282\u6307\u6570\u6CD5\uFF1A\u662F\u4EE5\u65F6\u95F4\u5E8F\u5217\u542B\u6709\u5B63\u8282\u6027\u5468\u671F\u53D8\u52A8\u7684\u7279\u5F81\uFF0C\u8BA1\u7B97\u63CF\u8FF0\u8BE5\u53D8\u52A8\u7684\u5B63\u8282\u53D8\u52A8\u6307\u6570\u7684\u65B9\u6CD5\u3002\u7EDF\u8BA1\u4E2D\u7684\u5B63\u8282\u6307\u6570\u9884\u6D4B\u6CD5\u5C31\u662F\u6839\u636E\u65F6\u95F4\u5E8F\u5217\u4E2D\u7684\u6570\u636E\u8D44\u6599\u6240\u5448\u73B0\u7684\u5B63\u8282\u53D8\u52A8\u89C4\u5F8B\u6027\uFF0C\u5BF9\u9884\u6D4B\u76EE\u6807\u672A\u6765\u72B6\u51B5\u4F5C\u51FA\u9884\u6D4B\u7684\u65B9\u6CD5\u3002\u638C\u63E1\u4E86\u5B63\u8282\u53D8\u52A8\u89C4\u5F8B\uFF0C\u5C31\u53EF\u4EE5\u5229\u7528\u5B83\u6765\u5BF9\u5B63\u8282\u6027\u7684\u5546\u54C1\u8FDB\u884C\u5E02\u573A\u9700\u6C42\u91CF\u7684\u9884\u6D4B\u3002\u5229\u7528\u5B63\u8282\u6307\u6570\u9884\u6D4B\u6CD5\u8FDB\u884C\u9884\u6D4B\u65F6\uFF0C\u65F6\u95F4\u5E8F\u5217\u7684\u65F6\u95F4\u5355\u4F4D\u6216\u662F\u5B63\uFF0C\u6216\u662F\u6708\uFF0C\u53D8\u52A8\u5FAA\u73AF\u5468\u671F\u4E3A 4 \u5B63\u6216\u662F 12 \u4E2A\u6708\u3002\u670D\u88C5\u4E2D\u8BA1\u7B97\u516C\u53F8\u662F\uFF1A(\u6BCF\u6708\u5B9E\u9645\u4E1A\u7EE9/\u540C\u671F\u7D2F\u8BA1\u4E1A\u7EE9)*100%\u3002</li><li>\u8FDE\u5E26\u7387\uFF1A\u9500\u552E\u603B\u6570\u91CF\u9664\u4EE5\u9500\u552E\u5C0F\u7968\u6570\u91CF\u5F97\u51FA\u7684\u6BD4\u503C\u5C31\u79F0\u4F5C\u8FDE\u5E26\u7387\u3002\u8FDE\u5E26\u7387 = \u9500\u552E\u603B\u6570\u91CF \xF7 \u9500\u552E\u5C0F\u7968\u6570\u91CF(\u4F4E\u4E8E 1.3 \u8BF4\u660E\u6574\u4F53\u9644\u52A0\u5B58\u5728\u4E25\u91CD\u95EE\u9898)\u4E2A\u4EBA\u9500\u552E\u8FDE\u5E26\u7387= \u4E2A\u4EBA\u9500\u552E\u603B\u6570\u91CF \xF7 \u4E2A\u4EBA\u5C0F\u7968\u603B\u91CF(\u4F4E\u4E8E 1.3 \u8BF4\u660E\u4E2A\u4EBA\u9644\u52A0\u5B58\u5728\u95EE\u9898)\u3002</li><li>\u5BA2\u5355\u4EF7\uFF1A\u662F\u6307\u5E97\u94FA\u6BCF\u4E00\u4E2A\u987E\u5BA2\u5E73\u5747\u8D2D\u4E70\u5546\u54C1\u7684\u91D1\u989D\uFF0C\u4E5F\u5373\u662F\u5E73\u5747\u4EA4\u6613\u91D1\u989D\u3002\u5BA2\u5355\u4EF7\u7684\u8BA1\u7B97\u516C\u5F0F\u662F\uFF1A\u9500\u552E\u91D1\u989D \xF7 \u6210\u4EA4\u7B14\u6570\u3002</li></ol>',2);function t(a,_){return r}var n=i(e,[["render",t],["__file","\u4E00\u4E9B\u7F29\u5199.html.vue"]]);export{n as default};
